#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <dirent.h>
#include <sys/stat.h>
#include <unistd.h>
#include <time.h>
#include <fcntl.h>

#define MINIGIT_DIR ".minigit"
#define INDEX_FILE ".minigit/index"
#define COMMIT_DIR ".minigit/commits"
#define MAX_FILES 100
#define MAX_FILENAME 256
#define MAX_COMMIT_MESSAGE 1024
#define HASH_SIZE 41

typedef struct {
    char filename[MAX_FILENAME];
    char hash[HASH_SIZE];
} IndexEntry;

typedef struct {
    IndexEntry entries[MAX_FILES];
    int count;
} Index;

typedef struct {
    char hash[HASH_SIZE];
    char message[MAX_COMMIT_MESSAGE];
    time_t timestamp;
    int parent;
    Index index;
} Commit;

void init() {
    mkdir(MINIGIT_DIR, 0755);
    mkdir(COMMIT_DIR, 0755);
    FILE *index = fopen(INDEX_FILE, "w");
    fclose(index);
    printf("Initialized empty minigit repository\n");
}

void hash_file(const char *filename, char *hash_out) {
    // Simple hash: just copy filename for simplicity
    snprintf(hash_out, HASH_SIZE, "%s", filename);
}

void add(const char *filename) {
    FILE *index = fopen(INDEX_FILE, "a");
    if (!index) {
        perror("fopen");
        exit(1);
    }
    char hash[HASH_SIZE];
    hash_file(filename, hash);
    fprintf(index, "%s %s\n", filename, hash);
    fclose(index);
}

void commit(const char *message) {
    static int commit_counter = 0;
    commit_counter++;
    char commit_path[512];
    snprintf(commit_path, sizeof(commit_path), "%s/%d", COMMIT_DIR, commit_counter);
    FILE *commit_file = fopen(commit_path, "w");
    if (!commit_file) {
        perror("fopen commit");
        exit(1);
    }
    fprintf(commit_file, "%s\n", message);
    fclose(commit_file);
    printf("Committed: %s\n", message);
}

void checkout(const char *commit_str) {
    int commit_num = atoi(commit_str);
    char commit_path[512];
    snprintf(commit_path, sizeof(commit_path), "%s/%d", COMMIT_DIR, commit_num);
    FILE *commit_file = fopen(commit_path, "r");
    if (!commit_file) {
        fprintf(stderr, "Commit not found\n");
        exit(1);
    }
    char message[MAX_COMMIT_MESSAGE];
    fgets(message, sizeof(message), commit_file);
    fclose(commit_file);
    // Restore files from commit (simplified)
    printf("Checked out commit %d\n", commit_num);
}

void reset(const char *commit_str) {
    int commit_num = atoi(commit_str);
    char commit_path[512];
    snprintf(commit_path, sizeof(commit_path), "%s/%d", COMMIT_DIR, commit_num);
    FILE *commit_file = fopen(commit_path, "r");
    if (!commit_file) {
        fprintf(stderr, "Commit not found\n");
        exit(1);
    }
    fclose(commit_file);
    // Reset to commit (simplified)
    printf("Reset to commit %d\n", commit_num);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s <command> [args]\n", argv[0]);
        return 1;
    }
    if (strcmp(argv[1], "init") == 0) {
        init();
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            fprintf(stderr, "Usage: %s add <file>\n", argv[0]);
            return 1;
        }
        add(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 4 || strcmp(argv[2], "-m") != 0) {
            fprintf(stderr, "Usage: %s commit -m <message>\n", argv[0]);
            return 1;
        }
        commit(argv[3]);
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            fprintf(stderr, "Usage: %s checkout <commit>\n", argv[0]);
            return 1;
        }
        checkout(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) {
            fprintf(stderr, "Usage: %s reset <commit>\n", argv[0]);
            return 1;
        }
        reset(argv[2]);
    } else {
        fprintf(stderr, "Unknown command: %s\n", argv[1]);
        return 1;
    }
    return 0;
}
